import { describe, it, expect } from '@a0n/gnosis/test';
import { GnosisRegistry } from '../runtime/registry';
import {
  PISOT_FIB,
  PISOT_MAX_INDEX,
  pisotF,
  pisotCassini,
  pisotCheck,
  pisotInit,
  pisotFork,
  pisotRace,
  pisotSmooth,
  pisotRun,
  compilePisotNodes,
  registerPisotPrimitive,
} from './pisot-primitive';
import { registerBettiHandlers } from './handlers';

describe('pisot-primitive :: Fibonacci table', () => {
  it('matches Lean F: F[0]=F[1]=1, F[n+2]=F[n+1]+F[n]', () => {
    expect(pisotF(0)).toBe(1);
    expect(pisotF(1)).toBe(1);
    expect(pisotF(2)).toBe(2);
    expect(pisotF(3)).toBe(3);
    expect(pisotF(4)).toBe(5);
    expect(pisotF(10)).toBe(89);
  });

  it('stays within u32 safety at the cap', () => {
    expect(PISOT_FIB[PISOT_MAX_INDEX]).toBeLessThan(2 ** 32);
  });

  it('throws on out-of-range index', () => {
    expect(() => pisotF(-1)).toThrow();
    expect(() => pisotF(PISOT_MAX_INDEX + 1)).toThrow();
  });
});

describe('pisot-primitive :: Cassini invariant', () => {
  it('holds for every index in range', () => {
    for (let n = 1; n < PISOT_MAX_INDEX; n++) {
      expect(pisotCassini(n)).toBe(true);
    }
  });

  it('pisotCheck does not throw on valid index', () => {
    expect(() => pisotCheck(10)).not.toThrow();
  });
});

describe('pisot-primitive :: CPU ops', () => {
  it('fork pushes a slot onto the stack', () => {
    const s = pisotFork(pisotInit(), 5);
    expect(s.stack).toEqual([5]);
    expect(s.lastOp).toBe('fork');
  });

  it('race keeps the higher Fibonacci slot (Vickrey winner)', () => {
    let s = pisotFork(pisotInit(), 5);
    s = pisotFork(s, 7);
    s = pisotRace(s);
    expect(s.stack).toEqual([7]);
  });

  it('race throws when fewer than two slots', () => {
    expect(() => pisotRace(pisotInit())).toThrow();
  });

  it('smooth gives a valid Zeckendorf decomposition', () => {
    const indices = pisotSmooth(100);
    // Reconstruct from PISOT_FIB and verify no adjacent indices.
    const sum = indices.reduce((acc, i) => acc + PISOT_FIB[i], 0);
    expect(sum).toBe(100);
    for (let i = 0; i < indices.length - 1; i++) {
      expect(indices[i] - indices[i + 1]).toBeGreaterThan(1);
    }
  });

  it('smooth of 0 is empty', () => {
    expect(pisotSmooth(0)).toEqual([]);
  });

  it('pisotRun executes a full program (fork/fork/race/smooth)', () => {
    const state = pisotRun([
      { op: 'fork', arg: 5 },
      { op: 'fork', arg: 7 },
      { op: 'race' },
      { op: 'smooth', arg: 10 },
      { op: 'check', arg: 8 },
    ]);
    // race result 7, then smooth(10) = [5, 2] (F[5]=8, F[2]=2)
    expect(state.stack[0]).toBe(7);
    expect(state.stack.slice(1).reduce((a, i) => a + PISOT_FIB[i], 0)).toBe(10);
  });
});

describe('pisot-primitive :: Betti integration', () => {
  it('registerPisotPrimitive wires handler labels', () => {
    const registry = new GnosisRegistry();
    registerPisotPrimitive(registry);
    expect(registry.hasHandler('Pisot')).toBe(true);
    expect(registry.hasHandler('PisotVickrey')).toBe(true);
  });

  it('registerBettiHandlers also registers Pisot (auto-wire)', () => {
    const registry = new GnosisRegistry();
    registerBettiHandlers(registry);
    expect(registry.hasHandler('Pisot')).toBe(true);
  });

  it('compilePisotNodes emits bytecode from a GraphAST', () => {
    const nodes = new Map<string, any>([
      ['a', { labels: ['Pisot'], properties: { op: 'fork', arg: '5' } }],
      ['b', { labels: ['Pisot'], properties: { op: 'fork', arg: '7' } }],
      ['c', { labels: ['Pisot'], properties: { op: 'race' } }],
      ['d', { labels: ['Other'], properties: {} }],
    ]);
    const bytecode = compilePisotNodes({ nodes });
    expect(bytecode.kind).toBe('pisot-bytecode');
    expect(bytecode.instructions.length).toBe(3);
    expect(bytecode.instructions[0]).toEqual({ op: 'fork', arg: 5 });
    expect(bytecode.instructions[2]).toEqual({ op: 'race' });
  });

  it('Pisot handler threads state through fork -> race', async () => {
    const registry = new GnosisRegistry();
    registerPisotPrimitive(registry);
    const handler = registry.getHandler('Pisot')!;
    let state = await handler(null, { op: 'fork', arg: '5' });
    state = await handler(state, { op: 'fork', arg: '7' });
    state = await handler(state, { op: 'race' });
    expect(state.stack).toEqual([7]);
  });
});
